sparql_query:
PREFIX goo:    <https://ucf-henat.github.io/GeoOutageOnto/#>
PREFIX gokg:   <http://example.org/resource#>
PREFIX xsd:    <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf:    <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:   <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?county
WHERE {
  VALUES ?record { gokg:customeroutagerecord.12086.2018-06-11T19-00-00Z }
  ?record a goo:CustomerOutageRecord ;
          goo:representsCounty ?county ;
          goo:recordDateTime ?recordDate .
  ?ntl a goo:NTLImage ;
       goo:representsCounty ?county ;
       goo:acquisitionDateTime ?imageDate ;
       goo:hasOutageMap ?map .
  ?map a goo:OutageMap .
  FILTER (SUBSTR(STR(?recordDate), 1, 10) = SUBSTR(STR(?imageDate), 1, 10))
}
LIMIT 10
